function renderPortfolioRisk(){const el=$('#portfolioRiskGrid');if(!el)return;const rows=(app.ownedStocks||[]).map(row=>{const q=row.quote,price=Number(q?.price)||Number(row.buyPrice)||0,qty=Number(row.quantity)||0,value=price*qty,cost=Number(row.buyPrice||0)*qty;return{symbol:q?.ticker||row.symbol,company:q?.company||row.symbol,value,cost,change:Number(q?.change_percent)||0,currency:q?.currency||'USD'}}).filter(x=>x.value>0||x.cost>0);if(!rows.length){el.innerHTML='<div class="empty">매수가와 수량이 있는 보유 종목을 등록하면 위험 분석을 시작합니다.</div>';return}const groups=Object.entries(rows.reduce((acc,row)=>{(acc[row.currency]||(acc[row.currency]=[])).push(row);return acc},{})),shock=Number($('#portfolioShock')?.value??-20);el.innerHTML=groups.map(([currency,items])=>{const total=items.reduce((s,x)=>s+x.value,0),cost=items.reduce((s,x)=>s+x.cost,0),top=[...items].sort((a,b)=>b.value-a.value)[0],scenario=total*(1+shock/100),format=value=>`${esc(currency)} ${Number(value).toLocaleString('ko-KR',{maximumFractionDigits:2})}`;return`<section class="currency-risk-group"><div class="risk-summary"><div><span>${esc(currency)} 평가 금액</span><strong>${format(total)}</strong></div><div><span>평가 손익</span><strong class="${total-cost>=0?'income':'negative'}">${total-cost>=0?'+':''}${format(total-cost)}</strong></div><div><span>최대 집중</span><strong>${esc(top.symbol)} ${total?Math.round(top.value/total*100):0}%</strong></div><div><span>${shock}% 시나리오</span><strong>${format(scenario)}</strong></div></div>${items.sort((a,b)=>b.value-a.value).map(x=>`<div class="risk-bar"><span>${esc(x.symbol)}</span><i><b style="width:${Math.max(3,total?x.value/total*100:0)}%"></b></i><strong>${total?Math.round(x.value/total*100):0}%</strong></div>`).join('')}<div class="stocksetup">${top.value/total>.6?'한 종목 비중이 60%를 넘어요. 가격 변동이 해당 통화 자산에 크게 반영됩니다.':'해당 통화 내 종목 집중도는 한 종목 60% 미만입니다.'}</div></section>`}).join('')+`<div class="stocksetup">통화가 다른 평가 금액은 환율 없이 합산하지 않았습니다. 현재 ${groups.length}개 통화 그룹을 각각 계산했어요.</div>`}
async function askNexusAnalyst(){if(!app.user){app.pendingRoute={page:'stocks'};openAuthModal();return}const sec=v10CurrentSecurity(),question=$('#stockOsQuestion').value.trim();if(!sec)return showToast('먼저 종목 방을 선택해 주세요.');if(!question)return showToast('분석할 질문을 입력해 주세요.');const btn=$('#stockOsAskButton'),out=$('#nexusAnalystResult');btn.disabled=true;btn.textContent='근거 수집 중…';out.innerHTML='<div class="empty">공시·뉴스·가격·개인 메모를 같은 종목 기준으로 대조하고 있습니다.</div>';try{const thesis=v10CurrentThesis(),result=await invokeStock({mode:'analyst',question,symbol:sec.ticker,security_key:sec.security_key,security:sec,thesis,history:v10CurrentRoom()?.state?.messages||[]});renderAnalystResult(result.analysis||result);const room=ensureStockRoom(sec);room.state={...(room.state||{}),messages:[...(room.state?.messages||[]),{role:'user',content:question,at:v10Now()},{role:'nexus',content:result.analysis?.verdict||result.answer||'',at:v10Now()}].slice(-30)};room.updated_at=v10Now();if(app.user&&app.v10.workspaceReady)app.sbClient.from(V10_TABLES.rooms).upsert({...room,user_id:app.user.id},{onConflict:'user_id,security_key'}).then(({error})=>error&&console.warn(error));$('#stockOsQuestion').value='';clearSavedDraft('nexus-v10-draft-stock-question');renderStockRoomHistory()}catch(error){out.innerHTML=`<div class="empty">분석 실패: ${esc(error.message||String(error))}</div>`}finally{btn.disabled=false;btn.textContent='근거 분석'}}
