function renderInvestmentReview(){const el=$('#investmentReviewGrid');if(!el)return;const month=localDateString().slice(0,7),decisions=(app.v10.documents||[]).filter(x=>x.doc_type==='decision'&&String(x.created_at||x.source_date||'').slice(0,7)===month),active=(app.v10.theses||[]).filter(x=>x.status==='active').length,weakened=(app.v10.theses||[]).filter(x=>['weakened','invalidated'].includes(x.status)).length,questions=(app.v10.rooms||[]).reduce((sum,r)=>sum+(r.state?.messages||[]).filter(x=>x.role==='user'&&String(x.at||'').slice(0,7)===month).length,0),movers=[...(app.ownedStocks||[])].filter(x=>x.quote).sort((a,b)=>Math.abs(Number(b.quote.change_percent||0))-Math.abs(Number(a.quote.change_percent||0))),top=movers[0];const rows=[['판단 기록',`${decisions.length}건`],['유효 투자 논리',`${active}개`],['재검토 필요',`${weakened}개`],['NEXUS 질문',`${questions}건`]];el.innerHTML=rows.map(([a,b])=>`<div class="review-item"><div><span>${esc(a)}</span><strong>${esc(b)}</strong></div></div>`).join('')+(top?`<div class="review-item wide"><span>가장 큰 최근 변동</span><strong>${esc(top.quote.ticker||top.symbol)} ${Number(top.quote.change_percent)>=0?'+':''}${Number(top.quote.change_percent).toFixed(2)}%</strong><p>가격 변화만으로 판단을 고정하지 말고 투자 논리·공시·재무를 다시 확인하세요.</p></div>`:'')+(decisions[0]?`<div class="review-item wide"><span>최근 판단 메모</span><strong>${esc(decisions[0].title||'매매 판단')}</strong><p>${esc(String(decisions[0].content||'').slice(0,180))}</p></div>`:'')}
