async function runDailyStockIntelligence(){
  if(!navigator.onLine||!app.user||!app.sbClient||!app.v10.workspaceReady)return;
  const today=localDateString(),last=localStorage.getItem('nexus-v10-daily-intelligence');
  if(last===today)return;
  const positionKeys=new Set((app.v10.positions||[]).map(x=>x.security_key));
  const targets=v10UniqueBy([v10CurrentSecurity(),...(app.v10.securities||[]).filter(x=>positionKeys.has(x.security_key))].filter(Boolean),x=>x.security_key).slice(0,3);
  let eventCount=0;
  for(const sec of targets){
    try{
      const result=await invokeStock({mode:'disclosures',symbol:sec.ticker,security:sec});
      const rows=(result.events||[]).map(x=>({...x,user_id:app.user.id,security_key:sec.security_key}));
      if(rows.length){
        const payload=rows.map(({id,...row})=>row),{data,error}=await app.sbClient.from(V10_TABLES.events).upsert(payload,{onConflict:'user_id,security_key,source_url,title'}).select();
        if(error)throw error;
        app.v10.events=v10UniqueBy([...(data||[]),...app.v10.events],x=>`${x.security_key}|${x.source_url}|${x.title}`);
        eventCount+=rows.length;
      }
    }catch(error){console.warn(`[NEXUS daily intelligence] ${sec.ticker}`,error)}
  }
  try{const result=await invokeStock({mode:'macro'});app.v10.macro=result.items||app.v10.macro}catch(error){console.warn('[NEXUS daily macro]',error)}
  localStorage.setItem('nexus-v10-daily-intelligence',today);
  v10PersistLocal();generateNexusAlerts();renderStockEvents();renderMacroContext();renderNexusToday(true);
  addLocalAlert('stock-daily','오늘의 주식 리서치 점검 완료',targets.length?`보유·선택 종목 ${targets.length}개와 시장 환경을 확인했어요. 신규 수집 이벤트 ${eventCount}건입니다.`:'리서치 종목을 등록하면 하루 한 번 공시와 시장 환경을 확인합니다.','info',{page:'stocks'});
  v10PersistLocal();renderAlerts();
}

/* ALERTS */
function localAlertId(kind,title){return `${kind}-${fnv1a(title)}`}
function addLocalAlert(kind,title,message,severity='info',action={}){const id=localAlertId(kind,title),existing=app.v10.alerts.find(x=>x.id===id&&!x.read_at);if(existing){existing.message=message;existing.created_at=v10Now();return}app.v10.alerts.unshift({id,user_id:app.user?.id||null,kind,title,message,severity,action,read_at:null,created_at:v10Now()})}
function generateNexusAlerts(){const prefs=app.v10.prefs,move=Number(prefs.stockMove)||10;(app.ownedStocks||[]).filter(x=>x.quote&&Math.abs(Number(x.quote.change_percent||0))>=move).forEach(x=>addLocalAlert('stock',`${x.quote.ticker||x.symbol} 변동 폭 확인`,`${x.quote.company||x.symbol} 전일 대비 ${Number(x.quote.change_percent)>=0?'+':''}${Number(x.quote.change_percent).toFixed(2)}%. 지연 가능 시세와 공시를 같이 확인하세요.`,'warning',{page:'stocks',securityKey:app.v10.securities.find(s=>s.ticker===x.quote.ticker)?.security_key}));const workouts=[...(app.fitnessRecords||[])].filter(x=>(x.type||x.kind||x.record_type)==='workout').sort((a,b)=>String(b.date||b.record_date).localeCompare(String(a.date||a.record_date))),gap=workouts[0]?Math.floor((Date.now()-new Date(`${workouts[0].date||workouts[0].record_date}T12:00:00`).getTime())/86400000):999;if(gap>=Number(prefs.workoutGap||5))addLocalAlert('fitness','운동 기록 확인',workouts[0]?`최근 운동 기록 후 ${gap}일이 지났어요.`:'아직 운동 기록이 없어요.','watch',{page:'fitness'});const goal=Number(app.myProfile?.monthlySpendingGoal)||0,expense=monthStats().expense;if(goal&&expense/goal*100>=Number(prefs.spendingThreshold||80))addLocalAlert('finance','월 지출 목표 확인',`이번 달 지출이 목표의 ${Math.round(expense/goal*100)}%에 도달했어요.`,'warning',{page:'finance'});if(prefs.systemAlert!==false&&app.lastDiagnostics?.fail)addLocalAlert('system','기능 자가진단 확인',`${app.lastDiagnostics.fail}개 항목이 통과하지 못했어요.`,'critical',{page:'system'});const recentCut=Date.now()-3*86400000;(app.v10.events||[]).filter(x=>new Date(`${x.event_date||''}T12:00:00`).getTime()>=recentCut).slice(0,4).forEach(x=>addLocalAlert('disclosure',`${x.title}`,`${x.source_type||'공시'} · ${x.event_date||'최근'} · 선택 종목의 투자 논리와 비교해 보세요.`,'info',{page:'stocks',securityKey:x.security_key}));v10PersistLocal();renderAlerts()}
function renderAlerts(){const list=$('#alertList'),count=$('#alertCount');if(!list)return;const rows=app.v10.alerts.slice(0,50),unread=rows.filter(x=>!x.read_at).length;count.hidden=!unread;count.textContent=unread>99?'99+':String(unread);list.innerHTML=rows.length?rows.map(x=>`<button class="alert-item ${esc(x.severity||'info')}" onclick="openAlert('${esc(x.id)}')"><i></i><div><strong>${esc(x.title)}</strong><span>${esc(x.message)}</span></div><time>${new Date(x.created_at||Date.now()).toLocaleDateString('ko-KR')}</time></button>`).join(''):'<div class="empty">확인할 알림이 없습니다.</div>'}
function toggleAlertDrawer(force){const el=$('#alertDrawer'),open=typeof force==='boolean'?force:!el.classList.contains('open');el.classList.toggle('open',open);el.setAttribute('aria-hidden',String(!open));if(open)renderAlerts()}
async function openAlert(id){const row=app.v10.alerts.find(x=>x.id===id);if(!row)return;row.read_at=v10Now();if(app.user&&app.v10.workspaceReady&&v10IsUuid(id))app.sbClient.from(V10_TABLES.alerts).update({read_at:row.read_at}).eq('id',id).eq('user_id',app.user.id);if(row.action?.securityKey){app.v10.selectedStockKey=row.action.securityKey;navigate('stocks');renderStockOS()}else if(row.action?.page)navigate(row.action.page);toggleAlertDrawer(false);v10PersistLocal();renderAlerts()}
async function markAllAlertsRead(){const now=v10Now();app.v10.alerts.forEach(x=>x.read_at=x.read_at||now);if(app.user&&app.v10.workspaceReady)await app.sbClient.from(V10_TABLES.alerts).update({read_at:now}).eq('user_id',app.user.id).is('read_at',null);v10PersistLocal();renderAlerts()}

/* TRASH / UNDO */
async function pushNexusTrash(entityType,entityId,payload){const row={id:createId(),user_id:app.user?.id||null,entity_type:entityType,entity_id:String(entityId),payload,deleted_at:v10Now(),expires_at:new Date(Date.now()+30*86400000).toISOString()};app.v10.trash.unshift(row);v10PersistLocal();if(app.user&&app.v10.workspaceReady){const{data,error}=await app.sbClient.from(V10_TABLES.trash).insert({...row,user_id:app.user.id}).select().single();if(!error&&data){app.v10.trash=app.v10.trash.map(x=>x.id===row.id?data:x);app.v10.lastTrashId=data.id}else if(error)console.warn(error)}else app.v10.lastTrashId=row.id;return app.v10.trash.find(x=>x.id===(app.v10.lastTrashId||row.id))||row}
function showUndo(message,undo){app.v10.undo={...undo,trashId:undo?.trashId||app.v10.lastTrashId};$('#undoMessage').textContent=message;$('#undoBar').classList.add('show');clearTimeout(showUndo.timer);showUndo.timer=setTimeout(()=>{$('#undoBar').classList.remove('show');app.v10.undo=null},10000);renderTrashList()}
async function undoLastDelete(){const undo=app.v10.undo;if(!undo)return;try{await restoreTrashPayload(undo.type,undo.payload);if(undo.trashId)await deleteTrashForever(undo.trashId,false);$('#undoBar').classList.remove('show');app.v10.undo=null;showToast('삭제한 기록을 되돌렸습니다.')}catch(error){showToast(`복원 실패: ${error.message}`)}}
async function restoreTrashPayload(type,payload){if(type==='transaction'){const row={...payload,user_id:app.user.id};const{data,error}=await app.sbClient.from('nexus_finance_transactions').upsert(row,{onConflict:'id'}).select().single();if(error)throw error;app.transactions.unshift({...data,amount:Number(data.amount)}) ;renderFinance();renderHome()}else if(type==='fitness'){const row=payload,p={id:row.id,user_id:app.user.id,client_key:fitnessClientKey(row),record_date:row.date,record_type:row.type,note:row.note,advice:row.advice||'',created_at:row.createdAt||v10Now()};const{data,error}=await app.sbClient.from(FITNESS_TABLE).upsert(p,{onConflict:'user_id,client_key'}).select().single();if(error)throw error;app.fitnessRecords.unshift(remoteFitnessToLocal(data));renderFitnessPage()}else if(type==='owned_stock'){app.ownedStocks.unshift(payload);writeLocal('nexus-owned-stocks-v82',app.ownedStocks);await migrateOwnedStocksToV10();renderOwnedStocks();renderStockOS()}else if(type==='stock_document'){if(app.user&&app.v10.workspaceReady){const{data,error}=await app.sbClient.from(V10_TABLES.documents).upsert({...payload,user_id:app.user.id},{onConflict:'id'}).select('id,user_id,security_key,doc_type,title,content,source_url,source_date,metadata,created_at,updated_at').single();if(error)throw error;app.v10.documents.unshift(data)}else app.v10.documents.unshift(payload);renderStockNotes()}else if(type==='fivem_resource'){app.fivemData.resources.unshift(payload);saveFiveMData();renderFiveMPage()}v10ScheduleSync()}
function renderTrashList(){const el=$('#trashList');if(!el)return;const rows=app.v10.trash.filter(x=>new Date(x.expires_at||Date.now()+1)>new Date()).slice(0,50);el.innerHTML=rows.length?rows.map(x=>`<div class="trash-row"><div><strong>${esc(({transaction:'거래',fitness:'운동·식단',owned_stock:'보유 종목',stock_document:'주식 노트',fivem_resource:'FiveM 리소스'}[x.entity_type]||x.entity_type))}</strong><span>${new Date(x.deleted_at).toLocaleString('ko-KR')} · 30일 보관</span></div><div class="trash-actions"><button onclick="restoreTrashItem('${esc(x.id)}')">복원</button><button onclick="deleteTrashForever('${esc(x.id)}')">영구 삭제</button></div></div>`).join(''):'<div class="empty">휴지통이 비어 있습니다.</div>'}
async function restoreTrashItem(id){const row=app.v10.trash.find(x=>x.id===id);if(!row)return;await restoreTrashPayload(row.entity_type,row.payload);await deleteTrashForever(id,false);showToast('휴지통 기록을 복원했습니다.')}
async function deleteTrashForever(id,notify=true){app.v10.trash=app.v10.trash.filter(x=>x.id!==id);if(app.user&&app.v10.workspaceReady)await app.sbClient.from(V10_TABLES.trash).delete().eq('id',id).eq('user_id',app.user.id);v10PersistLocal();renderTrashList();if(notify)showToast('휴지통에서 영구 삭제했습니다.')}
async function emptyNexusTrash(){if(!confirm('휴지통의 모든 기록을 영구 삭제할까요?'))return;app.v10.trash=[];if(app.user&&app.v10.workspaceReady)await app.sbClient.from(V10_TABLES.trash).delete().eq('user_id',app.user.id);v10PersistLocal();renderTrashList();showToast('휴지통을 비웠습니다.')}

/* FIVEM PROJECT WORKSPACE */
async function createFiveMProject(){const name=prompt('FiveM 프로젝트 이름','Music-Pack');if(!name)return;const root=prompt('프로젝트 루트 경로','C:\\Music-Pack\\resources\\')||'';const row={id:createId(),user_id:app.user?.id||null,name:name.trim(),root_path:root,status:'active',metadata:{selected:true},created_at:v10Now(),updated_at:v10Now()};app.v10.projects.forEach(x=>x.metadata={...(x.metadata||{}),selected:false});app.v10.projects.unshift(row);v10PersistLocal();if(app.user&&app.v10.workspaceReady){const{data,error}=await app.sbClient.from(V10_TABLES.projects).insert({...row,user_id:app.user.id}).select().single();if(!error&&data)app.v10.projects[0]=data;else if(error)console.warn(error)}renderFiveMProjects();showToast('FiveM 프로젝트를 추가했습니다.')}
function selectedFiveMProject(){return app.v10.projects.find(x=>x.metadata?.selected)||app.v10.projects[0]||null}
async function selectFiveMProject(id){app.v10.projects.forEach(x=>x.metadata={...(x.metadata||{}),selected:x.id===id});v10PersistLocal();if(app.user&&app.v10.workspaceReady){const selected=app.v10.projects.find(x=>x.id===id);if(selected)await app.sbClient.from(V10_TABLES.projects).update({metadata:selected.metadata,updated_at:v10Now()}).eq('id',id).eq('user_id',app.user.id)}renderFiveMProjects()}
async function recordFiveMRun(runType,payload={}){const project=selectedFiveMProject();if(!project)return;let metric=null,resource='';if(runType==='resmon'){metric=payload.rows?.[0]?.ms??null;resource=payload.rows?.[0]?.resource||''}if(runType==='profiler'){metric=payload.rows?.[0]?.maxMs??null;resource=payload.rows?.[0]?.resource||''}if(runType==='script'){resource='붙여넣은 스크립트'}if(runType==='zip'){resource=payload.resource||payload.name||''}const row={id:createId(),user_id:app.user?.id||null,project_id:project.id,resource_name:resource,run_type:runType,metric_ms:metric,risk:payload.risk||(Number.isFinite(Number(metric))&&Number(metric)>=1.5?'high':'unknown'),summary:payload.summary||'',payload,created_at:v10Now()};app.v10.runs.unshift(row);v10PersistLocal();if(app.user&&app.v10.workspaceReady){const{data,error}=await app.sbClient.from(V10_TABLES.runs).insert({...row,user_id:app.user.id}).select().single();if(!error&&data)app.v10.runs[0]=data;else if(error)console.warn(error)}renderFiveMProjects()}
function renderFiveMProjects(){const list=$('#fivemProjectList'),summary=$('#fivemProjectSummary'),history=$('#fivemRunHistory');if(!list)return;const selected=selectedFiveMProject();list.innerHTML=app.v10.projects.length?app.v10.projects.map(p=>`<div class="fivem-project-item ${p.id===selected?.id?'active':''}"><button onclick="selectFiveMProject('${p.id}')"><strong>${esc(p.name)}</strong><span>${esc(p.root_path||'경로 미입력')} · ${esc(p.status)}</span></button><button onclick="removeFiveMProject('${p.id}')">×</button></div>`).join(''):'<div class="empty">프로젝트를 추가하면 검사 결과를 한곳에 묶을 수 있어요.</div>';if(!selected){summary.className='empty';summary.textContent='프로젝트를 선택하면 검사 이력과 개선률이 표시됩니다.';history.innerHTML='';return}const rows=app.v10.runs.filter(x=>x.project_id===selected.id),byResource={};rows.filter(x=>Number.isFinite(Number(x.metric_ms))).forEach(x=>(byResource[x.resource_name]||(byResource[x.resource_name]=[])).push(x));const comparisons=Object.entries(byResource).map(([resource,r])=>{const sorted=r.sort((a,b)=>new Date(a.created_at)-new Date(b.created_at)),first=Number(sorted[0].metric_ms),last=Number(sorted.at(-1).metric_ms),improvement=first?((first-last)/first*100):0;return{resource,first,last,improvement}}).filter(x=>x.resource);summary.className='';summary.innerHTML=`<div class="risk-summary"><div><span>프로젝트</span><strong>${esc(selected.name)}</strong></div><div><span>검사 이력</span><strong>${rows.length}건</strong></div><div><span>추적 리소스</span><strong>${Object.keys(byResource).length}개</strong></div><div><span>상태</span><strong>${esc(selected.status)}</strong></div></div>${comparisons.map(x=>`<div class="risk-bar"><span>${esc(x.resource)}</span><i><b style="width:${Math.min(100,Math.max(5,Math.abs(x.improvement)))}%"></b></i><strong class="${x.improvement>=0?'improvement-good':'improvement-bad'}">${x.first.toFixed(3)} → ${x.last.toFixed(3)} ms (${x.improvement>=0?'+':''}${x.improvement.toFixed(1)}%)</strong></div>`).join('')}`;history.innerHTML=rows.slice(0,20).map(x=>`<div class="fivem-run-row"><strong>${esc(x.run_type)}</strong><span>${esc(x.resource_name||x.summary||'검사 결과')} · ${new Date(x.created_at).toLocaleString('ko-KR')}</span><b>${x.metric_ms!=null?`${Number(x.metric_ms).toFixed(3)}ms`:esc(x.risk)}</b></div>`).join('')}
async function removeFiveMProject(id){if(!confirm('프로젝트와 연결된 이력 표시를 제거할까요?'))return;app.v10.projects=app.v10.projects.filter(x=>x.id!==id);if(app.user&&app.v10.workspaceReady)await app.sbClient.from(V10_TABLES.projects).delete().eq('id',id).eq('user_id',app.user.id);renderFiveMProjects()}

/* V10 BACKUP SNAPSHOT */
function v10CloudSnapshot(){return{preferences:app.v10.prefs,workspace:v10WorkspacePayload(),securities:app.v10.securities,positions:app.v10.positions,rooms:app.v10.rooms,theses:app.v10.theses,documents:app.v10.documents,events:app.v10.events,alerts:app.v10.alerts,trash:app.v10.trash,projects:app.v10.projects,runs:app.v10.runs}}
exportNexusBackup=async function(){const payload={schema:NEXUS_BACKUP_SCHEMA,version:'10.0',buildId:BUILD_ID,exportedAt:v10Now(),displayName:DISPLAY_NAME,localStorage:collectNexusLocalState(),finance:app.user?{profile:{...app.financeProfile},transactions:app.transactions.map(tx=>({...tx}))}:null,v10:v10CloudSnapshot()};const stamp=localDateString().replaceAll('-','');downloadBlob(new Blob([JSON.stringify(payload,null,2)],{type:'application/json'}),`NEXUS_BACKUP_JINSEO_V10_${stamp}.json`);if($('#backupStatus'))$('#backupStatus').textContent=`${new Date().toLocaleString('ko-KR')} · V10 전체 백업 JSON을 만들었습니다.${app.user?' Finance·Stock OS 스냅샷 포함.':' 로그인 데이터는 제외.'}`;showToast('NEXUS V10 전체 백업 파일을 만들었습니다.')}
const handleNexusBackupFileV93=handleNexusBackupFile;handleNexusBackupFile=async function(file){await handleNexusBackupFileV93(file);const v10=app.pendingBackup?.payload?.v10,preview=$('#backupPreview');if(v10&&preview){const stats=[['Stock OS',`${(v10.securities||[]).length}종목 · ${(v10.documents||[]).length}노트`],['공시 이벤트',`${(v10.events||[]).length}건`],['FiveM 프로젝트',`${(v10.projects||[]).length}개 · 검사 ${(v10.runs||[]).length}건`],['NEXUS 알림',`${(v10.alerts||[]).length}건`]];preview.insertAdjacentHTML('beforeend',`<div class="backup-preview-grid v10-backup-preview">${stats.map(([a,b])=>`<div><span>${esc(a)}</span><strong>${esc(b)}</strong></div>`).join('')}</div>`)} }
async function restoreV10Snapshot(snapshot){if(!snapshot||!app.user||!app.v10.workspaceReady)return;const uid=app.user.id,upsert=async(table,rows,onConflict)=>{const clean=(rows||[]).map(row=>({...row,user_id:uid}));if(!clean.length)return;const{error}=await app.sbClient.from(table).upsert(clean,{onConflict});if(error)throw error};await upsert(V10_TABLES.prefs,[{user_id:uid,payload:snapshot.preferences||{},updated_at:v10Now()}],'user_id');await upsert(V10_TABLES.workspace,[{user_id:uid,payload:snapshot.workspace||{},updated_at:v10Now()}],'user_id');await upsert(V10_TABLES.securities,snapshot.securities,'user_id,security_key');await upsert(V10_TABLES.positions,snapshot.positions,'user_id,security_key');await upsert(V10_TABLES.rooms,snapshot.rooms,'user_id,security_key');await upsert(V10_TABLES.theses,snapshot.theses,'user_id,security_key');await upsert(V10_TABLES.documents,snapshot.documents,'id');await upsert(V10_TABLES.events,snapshot.events,'user_id,security_key,source_url,title');await upsert(V10_TABLES.alerts,(snapshot.alerts||[]).filter(x=>v10IsUuid(x.id)),'id');await upsert(V10_TABLES.projects,snapshot.projects,'id');await upsert(V10_TABLES.runs,snapshot.runs,'id')}
restorePendingBackup=async function(mode='local'){const pending=app.pendingBackup;if(!pending?.payload)return showToast('복구할 백업 파일이 없습니다.');const payload=pending.payload;try{Object.entries(payload.localStorage||{}).forEach(([key,val])=>{if(key.startsWith('nexus-')&&typeof val==='string')localStorage.setItem(key,val)});let message='';if(mode==='all'&&payload.finance&&app.user){const uid=app.user.id,profile={user_id:uid,cash_balance:Number(payload.finance.profile?.cash_balance)||0,bank_balance:Number(payload.finance.profile?.bank_balance)||0,savings_balance:Number(payload.finance.profile?.savings_balance)||0,loan_balance:Number(payload.finance.profile?.loan_balance)||0,card_due_balance:Number(payload.finance.profile?.card_due_balance)||0};const{error:profileError}=await app.sbClient.from('nexus_finance_profile').upsert(profile,{onConflict:'user_id'});if(profileError)throw profileError;const incoming=(payload.finance.transactions||[]).map(tx=>({user_id:uid,tx_date:tx.tx_date,tx_type:tx.tx_type,account:tx.account,category:tx.category,amount:Number(tx.amount)||0,memo:tx.memo||''})).filter(tx=>tx.tx_date&&tx.amount>0);const fresh=[];for(const tx of incoming)if(!isDuplicateTransactionCandidate(tx)&&!fresh.some(existing=>transactionFingerprint(existing)===transactionFingerprint(tx)))fresh.push(tx);if(fresh.length){const{error}=await app.sbClient.from('nexus_finance_transactions').insert(fresh);if(error)throw error}message+=` Finance 새 거래 ${fresh.length}건.`}if(mode==='all'&&payload.v10&&app.user){await restoreV10Snapshot(payload.v10);message+=' Stock OS·설정·FiveM 이력 복원.'}if($('#backupStatus'))$('#backupStatus').textContent=`${pending.fileName} 복원 완료.${message} 페이지를 새로 불러옵니다.`;showToast('NEXUS 백업을 복원했습니다.');setTimeout(()=>location.reload(),900)}catch(error){console.error(error);if($('#backupStatus'))$('#backupStatus').textContent=`복구 실패: ${error.message}`;showToast('백업 파일을 복원하지 못했습니다.')}}

