const addOwnedStockV93=addOwnedStock;addOwnedStock=async function(){await addOwnedStockV93();await migrateOwnedStocksToV10();v10ScheduleSync();renderStockOS();generateNexusAlerts()};
const removeOwnedStockV93=removeOwnedStock;removeOwnedStock=async function(id){const row=app.ownedStocks.find(x=>x.id===id);if(!row)return;await pushNexusTrash('owned_stock',id,row);removeOwnedStockV93(id);const sec=app.v10.securities.find(x=>x.ticker===row.quote?.ticker||x.ticker===String(row.symbol).toUpperCase());if(sec&&app.user&&app.v10.workspaceReady)await app.sbClient.from(V10_TABLES.positions).delete().eq('user_id',app.user.id).eq('security_key',sec.security_key);v10ScheduleSync();renderStockOS();showUndo('보유 종목을 삭제했습니다.',{type:'owned_stock',payload:row})};
const deleteTransactionV93=deleteTransaction;deleteTransaction=async function(id){const row=app.transactions.find(x=>x.id===id);if(!row||!app.user)return;if(!confirm('이 거래를 삭제할까요? 휴지통에서 30일 동안 복원할 수 있어요.'))return;await pushNexusTrash('transaction',id,row);const{error}=await app.sbClient.from('nexus_finance_transactions').delete().eq('id',id).eq('user_id',app.user.id);if(error)return showToast(`삭제 실패: ${error.message}`);app.transactions=app.transactions.filter(x=>x.id!==id);renderFinance();renderHome();showUndo('거래를 휴지통으로 이동했습니다.',{type:'transaction',payload:row})};
const deleteFitnessRecordV93=deleteFitnessRecord;deleteFitnessRecord=async function(id){const row=app.fitnessRecords.find(x=>x.id===id);if(!row)return;if(!confirm('이 운동·식단 기록을 삭제할까요? 휴지통에서 복원할 수 있어요.'))return;await pushNexusTrash('fitness',id,row);if(app.user&&app.fitnessCloudReady){const{error}=await app.sbClient.from(FITNESS_TABLE).delete().eq('id',id).eq('user_id',app.user.id);if(error)return showToast(`기록 삭제 실패: ${error.message}`)}app.fitnessRecords=app.fitnessRecords.filter(x=>x.id!==id);writeLocal('nexus-fitness-records',app.fitnessRecords);renderFitnessPage();renderHome();showUndo('운동·식단 기록을 휴지통으로 이동했습니다.',{type:'fitness',payload:row})};
const removeFiveMResourceV93=removeFiveMResource;removeFiveMResource=async function(id){const row=(app.fivemData.resources||[]).find(x=>x.id===id);if(!row)return;await pushNexusTrash('fivem_resource',id,row);removeFiveMResourceV93(id);showUndo('FiveM 리소스를 휴지통으로 이동했습니다.',{type:'fivem_resource',payload:row})};
const inspectFiveMCfgV93=inspectFiveMCfg;inspectFiveMCfg=function(){const r=inspectFiveMCfgV93();recordFiveMRun('cfg',{summary:'server.cfg 빠른 점검'});return r};
const inspectFiveMScriptV93=inspectFiveMScript;inspectFiveMScript=function(){const r=inspectFiveMScriptV93();recordFiveMRun('script',app.fivemData.lastInspection||{});return r};
const inspectFiveMResmonV93=inspectFiveMResmon;inspectFiveMResmon=function(){const r=inspectFiveMResmonV93();recordFiveMRun('resmon',app.fivemData.lastResmon||{});return r};
const inspectFiveMProfilerV93=inspectFiveMProfiler;inspectFiveMProfiler=function(){const r=inspectFiveMProfilerV93();recordFiveMRun('profiler',app.fivemData.lastProfiler||{});return r};
const inspectFiveMZipFileV93=inspectFiveMZipFile;inspectFiveMZipFile=async function(file){await inspectFiveMZipFileV93(file);recordFiveMRun('zip',app.fivemData.lastZip||{})};
const scheduleOwnedStockRefreshV93=scheduleOwnedStockRefresh;scheduleOwnedStockRefresh=function(){if(app.v10.prefs.autoRefreshStocks===false)return clearOwnedStockTimer();return scheduleOwnedStockRefreshV93()};
const showRouteV93=showRoute;showRoute=function(state){showRouteV93(state);if(state.page==='settings')renderSettingsPage();if(state.page==='stocks')renderStockOS();if(state.page==='fivem')renderFiveMProjects();if(state.page==='home'){applyHomeLayout();renderWeeklySummary()}generateNexusAlerts()};

const runNexusDiagnosticsV93=runNexusDiagnostics;runNexusDiagnostics=async function(){runNexusDiagnosticsV93();const rows=[];const add=(status,group,title,detail)=>rows.push({status,group,title,detail});try{const defs=mapHomeCards();add(Object.values(defs).filter(Boolean).length===7?'good':'bad','Personal Workspace','홈 카드 구성',`${Object.values(defs).filter(Boolean).length}/7 카드 연결`)}catch(e){add('bad','Personal Workspace','홈 카드 검사',e.message)}try{const keys=(app.v10.securities||[]).map(x=>x.security_key).filter(Boolean);add(new Set(keys).size===keys.length?'good':'bad','Stock OS','종목 독립 ID',`${keys.length}개 종목 · 중복 ${keys.length-new Set(keys).size}`)}catch(e){add('bad','Stock OS','종목 ID 검사',e.message)}try{const th=v10CurrentThesis(),sec=v10CurrentSecurity();const valid=!th||(Boolean(sec)&&th.security_key===sec.security_key&&['watch','active','weakened','invalidated','closed'].includes(th.status||'watch'));add(valid?'good':'bad','Stock OS','투자 논리 연결',th?`${th.status||'watch'} · ${th.security_key}`:'선택 종목 논리 대기')}catch(e){add('bad','Stock OS','투자 논리 검사',e.message)}try{add(typeof pushNexusTrash==='function'&&typeof undoLastDelete==='function'?'good':'bad','Personal Workspace','휴지통·되돌리기','30일 휴지통과 10초 실행 취소 함수 연결')}catch(e){add('bad','Personal Workspace','휴지통 검사',e.message)}const grid=$('#nexusDiagnosticsGrid');if(grid)grid.insertAdjacentHTML('beforeend',rows.map(diagnosticCard).join(''));const previous=app.lastDiagnostics||{total:0,pass:0,fail:0};app.lastDiagnostics={...previous,total:previous.total+rows.length,pass:previous.pass+rows.filter(x=>x.status==='good').length,fail:previous.fail+rows.filter(x=>x.status==='bad').length,at:v10Now()};writeLocal('nexus-last-diagnostics-v92',app.lastDiagnostics);showToast(`기능 자가진단 완료: ${app.lastDiagnostics.pass}/${app.lastDiagnostics.total} PASS`)};
const runSystemHealthCheckV93=runSystemHealthCheck;runSystemHealthCheck=async function(){await runSystemHealthCheckV93();if(app.user&&app.sbClient){const start=performance.now();try{const[{count:securityCount,error:se},{count:documentCount,error:de},{count:projectCount,error:pe}]=await Promise.all([app.sbClient.from(V10_TABLES.securities).select('security_key',{count:'exact',head:true}).eq('user_id',app.user.id),app.sbClient.from(V10_TABLES.documents).select('id',{count:'exact',head:true}).eq('user_id',app.user.id),app.sbClient.from(V10_TABLES.projects).select('id',{count:'exact',head:true}).eq('user_id',app.user.id)]);const error=se||de||pe;if(error)throw error;nexusSystemChecks.push({label:'V10 개인 워크스페이스',status:'good',value:`종목 ${securityCount||0} · 노트 ${documentCount||0} · FiveM ${projectCount||0}`,detail:'진서 계정의 설정·Stock OS·FiveM 프로젝트 테이블을 확인했어요.',ms:Math.round(performance.now()-start)})}catch(error){nexusSystemChecks.push({label:'V10 개인 워크스페이스',status:v10MissingTable(error)?'watch':'bad',value:v10MissingTable(error)?'SQL 설정 필요':'확인 필요',detail:v10MissingTable(error)?'NEXUS_V10_PERSONAL_STOCK_OS.sql을 한 번 실행해 주세요.':String(error.message||error),ms:Math.round(performance.now()-start)})}renderSystemCenter()}};
function initServiceWorkerUpdateNotice(){if(!('serviceWorker' in navigator))return;navigator.serviceWorker.ready.then(reg=>{const notify=()=>addLocalAlert('system','새 NEXUS 버전 준비','새 파일이 설치됐어요. 열려 있는 작업을 저장한 뒤 새로고침하면 적용됩니다.','info',{page:'system'});if(reg.waiting)notify();reg.addEventListener('updatefound',()=>{const worker=reg.installing;if(!worker)return;worker.addEventListener('statechange',()=>{if(worker.state==='installed'&&navigator.serviceWorker.controller){notify();v10PersistLocal();renderAlerts()}})})}).catch(()=>{})}
function initPersistentDrafts(){const bindings=[['#fivemScriptInput','nexus-v10-draft-fivem-script'],['#fivemWorkNotes','nexus-v10-draft-fivem-notes'],['#stockNoteTitle','nexus-v10-draft-stock-title'],['#stockNoteContent','nexus-v10-draft-stock-content'],['#stockOsQuestion','nexus-v10-draft-stock-question']];bindings.forEach(([selector,key])=>{const el=$(selector);if(!el)return;const saved=localStorage.getItem(key);if(saved&&!el.value)el.value=saved;el.addEventListener('input',()=>localStorage.setItem(key,el.value));});}
function clearSavedDraft(key){localStorage.removeItem(key)}

/* MAIN RENDER / INIT */
function renderV10All(){applyHomeLayout();renderWeeklySummary();renderStockOS();renderFiveMProjects();renderAlerts();if(app.currentPage==='settings')renderSettingsPage()}
function extendCommandPalette(){if(typeof NEXUS_MENU_COMMANDS!=='undefined'&&!NEXUS_MENU_COMMANDS.some(x=>x[0]==='NEXUS 설정')){NEXUS_MENU_COMMANDS.push(['NEXUS 설정','홈·동기화·알림·휴지통 설정','설정 개인화 홈 카드 동기화','⚙',()=>navigate('settings')],['NEXUS Analyst','종목별 투자 논리와 근거 분석','주식 AI 논리 공시 메모','↗',()=>{navigate('stocks');setTimeout(()=>$('#stockOsShell')?.scrollIntoView({behavior:'smooth'}),80)}]);nexusCommandStaticCache=null}}
function initV10(){console.info('[NEXUS] V10 Personal & Stock OS');ensureWeeklySummaryCard();mapHomeCards();applyHomeLayout();renderWeeklySummary();renderStockOS();renderFiveMProjects();extendCommandPalette();applyMenuVisibility();initPersistentDrafts();initServiceWorkerUpdateNotice();generateNexusAlerts();const start=app.v10.prefs.startPage;if(location.search===''&&location.hash===''&&start&&start!=='home'&&app.user)setTimeout(()=>navigate(start,{replace:true}),100);document.addEventListener('keydown',e=>{if(e.key==='Escape'){$('#quickRecordOverlay')?.classList.remove('show');$('#homeEditorOverlay')?.classList.remove('show');toggleAlertDrawer(false)}if(e.altKey&&!e.ctrlKey&&!e.metaKey&&!e.shiftKey&&e.code==='KeyQ'){e.preventDefault();openQuickRecord()}});setInterval(()=>{if(app.v10.dirty)v10ScheduleSync(0);generateNexusAlerts()},5*60*1000)}
document.addEventListener('DOMContentLoaded',()=>setTimeout(initV10,0));
